const Q_BIOLOGY_1993=[{"id": "objective>Biology>1993>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On what structure are the units of inheritance situated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Golgi bodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ribosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Endoplasmic reticulum</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The units of inheritance, known as genes, are located on chromosomes. Chromosomes are structures within cells that contain DNA, which carries genetic information. Therefore, the correct answer is 'Chromosomes'.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>1993>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Production of naked seeds is a distinctive feature of the group of plant called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">grasses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conifers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legumes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">palms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The production of naked seeds is a distinctive feature of conifers, which are a group of gymnosperms. Unlike angiosperms, which produce seeds enclosed in fruits, conifers produce seeds that are exposed on cones. Thus, the correct answer is 'conifers'.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>1993>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of these features do bryophytes differ from pteridophytes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Absence of flower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alternation of generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dependency on water for reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Presence of vascular system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bryophytes (mosses and liverworts) differ from pteridophytes (ferns) primarily in their dependency on water for reproduction. Bryophytes require water for sperm to swim to the egg for fertilization, while pteridophytes also need water but have a more complex life cycle. The other options do not distinctly separate the two groups. Therefore, the correct answer is 'Dependency on water for reproduction'.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>1993>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organs or cells components are common to both the sporophytes and the gametophytes of a fern?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rhizoids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chloroplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leaves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rhizoids are structures that anchor both the sporophytes and gametophytes of ferns to the substrate. They are not true roots but serve a similar function in providing stability. The other options (roots, chloroplasts, leaves) are not common to both life stages. Thus, the correct answer is 'Rhizoids'.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>1993>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following organism does a single cells performs all the function of movement, nutrition, growth , excretion, photosynthesis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Paramecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Euglena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Euglena is a single-celled organism that performs all the functions of movement, nutrition, growth, excretion, and photosynthesis. It has chloroplasts for photosynthesis and can also absorb nutrients from its environment. Paramecium and Amoeba are also single-celled but do not perform photosynthesis, while Spirogyra is a filamentous green algae. Therefore, the correct answer is 'Euglena'.</div>", "topic": "MICROORGANISMS"}, {"id": "objective>Biology>1993>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following organisms would glycogen be stored?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rattus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnifera</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Glycogen is a form of energy storage in animals and fungi. Among the given options, Rattus (a genus of rats) is an animal that stores glycogen in its liver and muscles. The other organisms listed (Spirogyra, Chlamydomonas, and Magnifera) do not store glycogen in the same way.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1993>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most successful group of animals in terms of diversity of species is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mollusca</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arthropoda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mammalia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">platyhelminthes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most successful group of animals in terms of diversity of species is the Arthropoda. This group includes insects, arachnids, crustaceans, and more, making it the largest phylum in the animal kingdom with millions of described species.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>1993>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Flame cells are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excretory system of worms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretory and respiratory systems of flatworms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secretory syustem of flatworms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretory system of flatworms</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flame cells are specialized excretory cells found in flatworms. They play a crucial role in the excretory system by helping to remove waste products from the body. The correct option states that they are the excretory system of flatworms.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>1993>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The spores of mucor are dispersed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">explosive mechanism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The spores of Mucor, a type of fungus, are primarily dispersed by wind. This is a common method of spore dispersal in fungi, allowing them to spread over large distances to colonize new environments.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1993>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the following is the correct order of the developmental stages?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 → 2→ 3→ 4→ 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5→ 1→ 3→ 2→ 4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2→ 1→ 3→ 4→ 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5→ 2→ 3→ 1→ 4</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order of the developmental stages is 5→ 2→ 3→ 1→ 4 <br/> <img src=\"1993/LYM89E.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : TOAD"}, {"id": "objective>Biology>1993>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Stage 3 breathes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">with the lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">with the external gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">with the internal gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">through the skin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stage 3 refers to the developmental stage of certain amphibians, such as frogs, which breathe with lungs as they mature from tadpoles. This is a key transition in their life cycle, moving from aquatic to terrestrial breathing.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>1993>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The butterfly is of great economic importance because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">of its use in scientific studies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it sucks nectar from flowers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it adds to the beauty of the enviroment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it polllinates flowers of crops and other plants</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Butterflies are important pollinators, which means they help in the reproduction of flowering plants by transferring pollen. This is crucial for the production of many crops and other plants, making them economically significant.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>1993>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Manufactured food in the plant is transported through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cambium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufactured food in plants, primarily in the form of sugars produced during photosynthesis, is transported through the phloem. The phloem is responsible for the distribution of nutrients and energy throughout the plant.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>1993>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">interveinal chlorosis is normally associated with the deficiency of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interveinal chlorosis, which is the yellowing of leaf tissue between the veins, is commonly associated with iron deficiency. Iron is essential for chlorophyll synthesis, and its deficiency leads to this specific symptom in plants.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1993>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Osmic acid boiled with a solution of food substance gave a black precipitate. This indicates the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fats and oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proteins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amino acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Osmic acid is used to test for the presence of fats and oils. When it reacts with these substances, it forms a black precipitate, indicating their presence in the food substance being tested.</div>", "topic": "N/A"}, {"id": "objective>Biology>1993>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the labelled parts is the diastema?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diastema is a gap or space between teeth, typically found in herbivorous animals. It is labelled 3</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>1993>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> This lower jaw is typical of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sheep</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rabbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dog</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lower jaw of a sheep is characterized by its structure, which is adapted for grinding plant material. Sheep have a unique dental formula that includes molars suited for this purpose, making 'sheep' the correct answer.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>1993>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The end products of the digestion of fats and oils in mammals are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maltose and fatty acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amino acids and glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fatty acid and fructose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fatty acids and glycerin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The end products of the digestion of fats and oils in mammals are fatty acids and glycerin. Fats are broken down by enzymes into these components, which can then be absorbed by the body.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>1993>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Blood is pumped into the right ventricle by the contraction of the auricle wall through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled 3 is the tricuspid valve and it regulates the movement of blood into the right ventricle.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1993>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> After circulation in the lungs, the blood returns to the left auricle through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After circulation in the lungs, the blood returns to the left auricle through the part labelled 6</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1993>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of blood in mammals is to transport</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excretory materials from tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbondioxide from lungs to tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">digested food from all the body tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen to the lungs</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of blood in mammals is to transport oxygen to the lungs. Blood carries oxygen from the lungs to the tissues and carbon dioxide from the tissues back to the lungs for exhalation. Therefore, the correct option is 'oxygen to the lungs'.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1993>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Members of the phylum protozoa use the contractile vacuole</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to remove excess food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for digestion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to remove excess water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Members of the phylum protozoa use the contractile vacuole to remove excess water. The contractile vacuole is an organelle that helps maintain osmotic balance by expelling excess water from the cell, which is crucial for survival in freshwater environments.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>1993>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The response shown by the tips of the root and shoot of a plant to the stimulus of gravity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">haptotropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phototropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrotropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geotropism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The response shown by the tips of the root and shoot of a plant to the stimulus of gravity is called geotropism (or gravitropism). Roots typically exhibit positive geotropism, growing downwards, while shoots exhibit negative geotropism, growing upwards.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1993>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct order of the vertebrae along the spinal column?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Axis → atlas → thoracic → lumbar → cervical → sacral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atlas → cervical → axis → thoracic → lumbar→ sacral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atlas → axis → cervical → thoracic → lumbar → sacral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Axis → atlas → cervical → thoracic → sacral → lumbar</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order is: Atlas → axis → cervical → thoracic → lumbar → sacral</div>", "topic": "SUPPORT AND MOVEMENT : SUPPORTING TISSUES IN ANIMALS"}, {"id": "objective>Biology>1993>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is TRUE of the process of conjugation in paramecium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Micronucleus disintegrates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Each ex-conjugant divides only once</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Macronucleus undergoes division</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Each micronucleus divides twice</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of conjugation in paramecium, the macronucleus undergoes division. During conjugation, two paramecia exchange genetic material, and the macronucleus divides to ensure that each ex-conjugant has the necessary genetic information for survival.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>1993>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bright colours of the comb and feathers in the peacock are for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sex differentiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beauty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">courtship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defence</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bright colors of the comb and feathers in the peacock are primarily for courtship. Male peacocks display their vibrant plumage to attract females during mating rituals. This is a common behavior in many species where males use visual signals to demonstrate their fitness and genetic quality to potential mates.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1993>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of the petal of a flower is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">attract pollination agents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the flower while still in bud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serve as landing stage for insects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the inner paisr from desiccation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main function of the petal of a flower is to attract pollination agents, such as bees, butterflies, and other insects. The bright colors and patterns of petals serve to lure these pollinators, which are essential for the reproduction of many flowering plants.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1993>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the mammal, the autonomic nervous system consists of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sympathetic and parasympathetic system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brain and spinal nerves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brain and cranial nerves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spinal cord and spinal nerves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the autonomic nervous system consists of the sympathetic and parasympathetic systems. The sympathetic system prepares the body for 'fight or flight' responses, while the parasympathetic system promotes 'rest and digest' functions. Together, they regulate involuntary bodily functions.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1993>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> In H, the cotyledons are carried above the soil because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the epicotyl grows faster than the hypocotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the hypocotyl grows faster than the epicotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both grow at the same rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the epicotyl outgrow the radicle</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In H, the cotyledons are carried above the soil because the hypocotyl grows faster than the epicotyl  . The epicotyl is the part of the seedling that develops into the stem and leaves, while the hypocotyl is the part that connects the cotyledons to the root. A faster-growing hypocotyl allows the cotyledons to emerge above the soil.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>1993>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the structure labelled G is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carry out initial photosynthesis for the seedlings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the young leaves from mechanical damage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the young leaves from sunlight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the young leaves from insects pest</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the structure labelled G is to carry out initial photosynthesis for the seedlings</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>1993>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When it is cold, the blood vessels of the skin</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dilates to increase the amount of blood flowing to the skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constrict to reduce the amount of blood flowing to the skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dilate to reduce the amount of blood flowing to the skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constrict to increase the amount of blood flowing to the skin</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When it is cold, the blood vessels of the skin constrict to reduce the amount of blood flowing to the skin. This process is known as vasoconstriction, which helps to conserve body heat by reducing blood flow to the surface of the skin.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1993>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which path does sound entering the human ear follow?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oval window → ossicles → ear drum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ear drum → oval window → ossicles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ear drum → ossicles → oval window</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ossicles → ear drum → oval window</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct path that sound entering the human ear follows is: Ear drum → ossicles → oval window. The sound waves first hit the ear drum, causing it to vibrate. These vibrations are then transmitted to the ossicles (three small bones in the middle ear) and finally to the oval window, which leads to the inner ear.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1993>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What would happen to a man whose pancreas has been surgically removed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The level of blood sugar would increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The glycogen content of the liver would increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">His blood pressure would decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">His weight would increase appreciably</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a man's pancreas has been surgically removed, the level of blood sugar would increase. The pancreas produces insulin, which regulates blood sugar levels. Without it, the body cannot effectively lower blood sugar, leading to hyperglycemia.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1993>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carnivorous plants are usually found in areas</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">which are deficient of nitrate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">which are deficient of oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">with low pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">where insects are abundant</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carnivorous plants are usually found in areas that are deficient of nitrate. These plants have adapted to obtain nutrients by trapping and digesting insects, which provide the nitrogen they lack from the soil.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1993>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the term used to describe the sum total of biotic and abiotic factors in the environment of the organism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecological niche</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term used to describe the sum total of biotic (living) and abiotic (non-living) factors in the environment of the organism is 'Ecosystem'. An ecosystem includes all the organisms in a given area as well as the physical environment with which they interact.</div>", "topic": "ECOLOGY"}, {"id": "objective>Biology>1993>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Important abiotic factors which affects all plants and animals in the habitat are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature and turbidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainfall and relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinity and wind direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature and rainfall</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Temperature and rainfall are both critical abiotic factors that affect all plants and animals in a habitat. Temperature influences metabolic rates and growth, while rainfall affects water availability, which is essential for survival. Therefore, option D (temperature and rainfall) is correct.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1993>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important physical factor which affects an organism living in the intertidal zone of the seashore is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wave action</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wave action is the most significant physical factor affecting organisms in the intertidal zone. It influences the distribution of organisms, their feeding habits, and their ability to survive in this dynamic environment. Therefore, option C (wave action) is correct.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1993>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At which trophic level would the highest accumulation of a non-biodegradable substance occur?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Primary producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tertiary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Primary consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secondary consumers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest accumulation of non-biodegradable substances, such as heavy metals or plastics, typically occurs at the tertiary consumer level. This is due to the process of biomagnification, where substances become more concentrated as they move up the food chain. Therefore, option B (Tertiary consumers) is correct.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1993>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two organisms of different species, living in close association but not dependent on each other are referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parasites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">symbionts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">autotrophs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organisms of different species living in close association but not dependent on each other are referred to as commensals. This relationship benefits one organism without significantly affecting the other. Therefore, option B (commensals) is correct.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>1993>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following instruments is NOT used in measuring abiotic factors in any habitat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Microscopic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hygrometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wind vane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A microscope is not used to measure abiotic factors; rather, it is used for examining biological specimens at a cellular level. The other instruments listed (thermometer, hygrometer, wind vane) are all used to measure abiotic factors such as temperature, humidity, and wind direction, respectively. </div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1993>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants adapted for life in salty marsh are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xerophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">halophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epiphytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants adapted for life in salty marshes are called halophytes. These plants have specialized adaptations that allow them to thrive in saline environments, such as salt glands that excrete excess salt and modified root systems that can tolerate high salinity.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>1993>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which group of plants would be the first colonizers in an ecological succession changing rocks to soil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mosses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ferns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lichens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grasses</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lichens are often the first colonizers in ecological succession, particularly in harsh environments like bare rocks. They are symbiotic organisms composed of fungi and algae or cyanobacteria, which can survive in extreme conditions and contribute to soil formation by breaking down rock.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>1993>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil fertility can be conserved and renewed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yearly monocropping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation and cover crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bush burning to remove unwanted debris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avoiding artificial manures</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil fertility can be conserved and renewed by crop rotation and cover crops. This practice helps maintain soil nutrients, reduces erosion, and prevents pest and disease cycles, leading to healthier soil over time.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>1993>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What ecological condition favours the breeding of blackflies?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fresh water habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water in ponds and swamps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water in small containers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fast flowing streams</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Blackflies breed in fast-flowing streams. They prefer clean, oxygen-rich water, which is typically found in such environments. The flowing water provides suitable conditions for their larvae to develop.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1993>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon monoxide poisons tissue by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constricting the blood vessels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">killing the cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combining with haemoglobin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rupturing the blood vessels</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon monoxide poisons tissue by combining with hemoglobin in the blood. This binding prevents hemoglobin from carrying oxygen, leading to tissue hypoxia and potentially fatal consequences.</div>", "topic": "POLLUTION"}, {"id": "objective>Biology>1993>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of discontinuous variation observed in man?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Skin colours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tongue rolling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Body weight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Height</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discontinuous variation refers to traits that fall into distinct categories, rather than a range. Tongue rolling is a classic example of discontinuous variation in humans, as individuals can either roll their tongues or cannot, with no intermediate forms. Skin color, body weight, and height are examples of continuous variation, as they can vary along a spectrum.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1993>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During blood transfusion, agglutination may occur when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contrasting antigens reacts with contrasting antibodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">similar antigens react with similar antibodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two different antigens react with each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two different antibodies react with each other</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agglutination during blood transfusion occurs when contrasting antigens on the red blood cells react with contrasting antibodies in the plasma. For example, if type A blood (which has A antigens) is transfused into a person with type B blood (which has anti-A antibodies), agglutination will occur due to this reaction.</div>", "topic": "HEREDITY : BLOOD GROUPS"}, {"id": "objective>Biology>1993>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the illustration above, the genotypes of the offsprings are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 heterozygous smooth : 2 homozygous smooth : 1 wrinkled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 homozygous smooth : 2 heterozygous smooth : 1 wrinkled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 homozygous smooth : 2 wrinkled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 heterozygous smooth : 2 wrinkled</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above refers to a PUNNETT SQUARE used in predicting the genotypic and phenotypic ratios of a cross.  <br/>  <br/> SS : Ss : sS : ss; the genotypic composition is; <br/>  <br/> 1 homozygous smooth : 2 heterozygous smooth : 1 wrinkled</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1993>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cold blooded animals are referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poikilothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polythermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homeostatic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cold-blooded animals, or ectotherms, are referred to as poikilothermic. This means their body temperature varies with the environment. In contrast, homothermic animals (or endotherms) maintain a constant body temperature regardless of environmental conditions.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>1993>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms has lost the pentadactyl limb structure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Frog</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pigeon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fish have lost the pentadactyl limb structure, which is characterized by having five digits. Instead, they have evolved fins adapted for swimming. Bats, frogs, and pigeons still exhibit variations of the pentadactyl limb structure, although adapted for their specific modes of life.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}];
